        self.label_6.setText(_translate("MainWindow", "Name:"))
        self.nameEdit.setToolTip(_translate("MainWindow", "Name (GFF: LocalizedName). CExoLocString. The displayed name of the item in inventory, stores, and dialogue. Engine reads via ReadFieldCExoLocString in CSWSItem::LoadDataFromGff (K1 @ 0x0055fcd0). Modders: set a custom name or leave empty to use the base item\'s default from baseitems.2da. Shown in the item description panel and store/container UI."))
        self.label_14.setText(_translate("MainWindow", "Tag:"))
        self.tagEdit.setToolTip(_translate("MainWindow", "Tag (GFF: Tag). CExoString. Unique identifier for this item when placed in the module. Engine reads via ReadFieldCExoString in LoadDataFromGff (K1 @ 0x0055fcd0). Scripts use GetItemByTag to target this item. Modders: leave blank for stackable/generic items; set a tag for scripted references. Duplicate tags in the same area can cause wrong item to be targeted."))
        self.tagGenerateButton.setToolTip(_translate("MainWindow", "Generate tag from ResRef. Copies the Template ResRef into the Tag field so they stay in sync. Use when you need to reference this item by tag in scripts; keep Tag unique per area."))
        self.tagGenerateButton.setText(_translate("MainWindow", "-"))
        self.label_38.setText(_translate("MainWindow", "ResRef:"))
        self.resrefEdit.setToolTip(_translate("MainWindow", "Template ResRef (GFF: TemplateResRef). ResRef (max 16 characters) of this item template; .uti extension implied. The engine stores ResRefs in 16 bytes. When the game loads an item (LoadFromTemplate @ 0x005608b0) it uses this to find the UTI file. Modders: must match the .uti filename; used by stores, loot tables, and GiveItem. Mismatch can cause missing or wrong item data."))
        self.resrefGenerateButton.setToolTip(_translate("MainWindow", "Generate ResRef from Tag. Copies the Tag into the Template ResRef field (max 16 characters). ResRef should match the UTI filename for the game to load the item correctly."))
        self.resrefGenerateButton.setText(_translate("MainWindow", "-"))
        self.label_53.setText(_translate("MainWindow", "Description:"))
        self.descEdit.setToolTip(_translate("MainWindow", "Description (GFF: DescIdentified). CExoLocString. Shown when the player examines an identified item. Engine reads via ReadFieldCExoLocString in LoadDataFromGff (K1 @ 0x0055fcd0). \"Description\" (unidentified) is also read; DescIdentified is the main one shown after identification. Modders: use for lore, usage hints, or flavor text."))
        self.label_39.setText(_translate("MainWindow", "Base Item:"))
        self.baseSelect.setToolTip(_translate("MainWindow", "Base Item (GFF: BaseItem). INT32. Engine reads via ReadFieldINT in LoadDataFromGff (K1 @ 0x0055fcd0). Row index into baseitems.2da; determines category (weapon, armor, usable), equip slots, model type, and default stats. Modders: must be a valid row; invalid indices can cause load failures or wrong visuals. Changing this changes the item\'s core behavior (e.g. blaster vs. lightsaber)."))
        self.label_40.setText(_translate("MainWindow", "Cost:"))
        self.costSpin.setToolTip(_translate("MainWindow", "Cost (GFF: Cost). Base sale/purchase price in credits. Stored as DWORD (0–4294967295); UI caps at 2147483647. The engine does not read this field in LoadDataFromGff (K1 @ 0x0055fcd0); it is written by SaveItem when saving. Store and barter typically use base item pricing plus AddCost (which the engine does read). Modders: set for toolset consistency and documentation; to affect in-game price, use Additional Cost. 0 = free. Very high values may display oddly in some UIs."))
        self.label_41.setText(_translate("MainWindow", "Additional Cost:"))
        self.additionalCostSpin.setToolTip(_translate("MainWindow", "Additional Cost (GFF: AddCost). DWORD. Engine reads via ReadFieldDWORD in LoadDataFromGff (K1 @ 0x0055fcd0). Extra credits added to base cost; combined with base item pricing for final store price. Modders: increase for upgraded or high-property items. Valid range 0–4294967295; UI caps at 2147483647."))
        self.label_42.setText(_translate("MainWindow", "Upgrade Level:"))
        self.upgradeSpin.setToolTip(_translate("MainWindow", "Upgrade Level (GFF: Upgrades). DWORD in engine (ReadFieldDWORD in LoadDataFromGff, K1 @ 0x0055fcd0). K1: bitfield for which upgrade slots are filled. K2: often used as upgrade tier (0–255). UI shows 0–255. Modders: must match base item; invalid values can break upgrade slots or display."))
        self.tabWidget.setTabText(self.tabWidget.indexOf(self.tab), _translate("MainWindow", "General"))
        self.label.setText(_translate("MainWindow", "Available Properties"))
        self.label.setToolTip(_translate("MainWindow", "Available properties from itemprops.2da (and related 2DAs). Add properties to define enchantments, damage bonuses, and special effects. The engine reads assigned properties from GFF PropertiesList (GetList in LoadDataFromGff, K1 @ 0x0055fcd0); each entry has PropertyName (WORD), Subtype (WORD), CostTable (BYTE), CostValue (WORD), Param1, Param1Value, ChanceAppear (BYTE), Useable (BYTE). Use the arrow buttons to assign."))
        self.addPropertyButton.setToolTip(_translate("MainWindow", "Add the selected available property to this item. Appends an entry to the GFF PropertiesList; the engine reads these in LoadDataFromGff (K1 @ 0x0055fcd0). Use Edit Property to set Subtype, CostValue, Param1, Param1Value, ChanceAppear, etc."))
        self.addPropertyButton.setText(_translate("MainWindow", "->"))
        self.removePropertyButton.setToolTip(_translate("MainWindow", "Remove the selected property from this item. Deletes the entry from the GFF PropertiesList. The item will no longer have that enchantment or effect in-game."))
        self.removePropertyButton.setText(_translate("MainWindow", "<-"))
        self.label_2.setText(_translate("MainWindow", "Assigned Properties"))
        self.label_2.setToolTip(_translate("MainWindow", "Assigned properties (GFF: PropertiesList). The engine reads this list in LoadDataFromGff (K1 @ 0x0055fcd0) via GetList(\"PropertiesList\"); each element has PropertyName (WORD), Subtype (WORD), CostTable (BYTE), CostValue (WORD), Param1, Param1Value (BYTE), ChanceAppear (BYTE), Useable (BYTE). Edit Property to adjust values. Order can affect display and some game logic."))
        self.assignedPropertiesList.setToolTip(_translate("MainWindow", "List of item properties on this item. Each row is one entry in GFF PropertiesList. Select a row and click Edit Property to change Subtype, CostValue, Param1, Param1Value, ChanceAppear, and other fields. The game applies these effects when the item is equipped or used."))
        self.editPropertyButton.setToolTip(_translate("MainWindow", "Open the property editor for the selected assigned property. Lets you set Subtype, CostTable, CostValue, Param1, Param1Value, ChanceAppear (0–100), Useable, and other fields. Required for configuring damage types, bonuses, and effect parameters."))
